-- Create view dbo.PIMS_PROPERTY_BOUNDARY_DISPOSITION_VW
PRINT N'Create view dbo.PIMS_PROPERTY_BOUNDARY_DISPOSITION_VW'
GO
CREATE VIEW [dbo].[PIMS_PROPERTY_BOUNDARY_DISPOSITION_VW] AS
SELECT prp.PROPERTY_ID
     , dsp.DISPOSITION_FILE_ID
     , dsp.DISPOSITION_FILE_STATUS_TYPE_CODE
     , prp.BOUNDARY
FROM   PIMS_PROPERTY                  prp                                              JOIN
       PIMS_DISPOSITION_FILE_PROPERTY dfp ON dfp.PROPERTY_ID         = prp.PROPERTY_ID JOIN
       PIMS_DISPOSITION_FILE          dsp ON dsp.DISPOSITION_FILE_ID = dfp.DISPOSITION_FILE_ID

GO
IF @@ERROR <> 0 SET NOEXEC ON
GO

