-- Create trigger dbo.PIMS_MAAINV_I_S_U_TR
PRINT N'Create trigger dbo.PIMS_MAAINV_I_S_U_TR'
GO
CREATE TRIGGER [dbo].[PIMS_MAAINV_I_S_U_TR] ON PIMS_MANAGEMENT_ACTIVITY_INVOICE INSTEAD OF UPDATE AS
SET NOCOUNT ON
BEGIN TRY
  IF NOT EXISTS(SELECT * FROM deleted) 
    RETURN;

  -- validate concurrency control
  if exists (select 1 from inserted, deleted where inserted.CONCURRENCY_CONTROL_NUMBER != deleted.CONCURRENCY_CONTROL_NUMBER+1 AND inserted.MANAGEMENT_ACTIVITY_INVOICE_ID = deleted.MANAGEMENT_ACTIVITY_INVOICE_ID)
    raiserror('CONCURRENCY FAILURE.',16,1)


  -- update statement
  update PIMS_MANAGEMENT_ACTIVITY_INVOICE
    set "MANAGEMENT_ACTIVITY_INVOICE_ID" = inserted."MANAGEMENT_ACTIVITY_INVOICE_ID",
      "MANAGEMENT_ACTIVITY_ID" = inserted."MANAGEMENT_ACTIVITY_ID",
      "INVOICE_DT" = inserted."INVOICE_DT",
      "INVOICE_NUM" = inserted."INVOICE_NUM",
      "DESCRIPTION" = inserted."DESCRIPTION",
      "PRETAX_AMT" = inserted."PRETAX_AMT",
      "GST_AMT" = inserted."GST_AMT",
      "PST_AMT" = inserted."PST_AMT",
      "TOTAL_AMT" = inserted."TOTAL_AMT",
      "IS_PST_REQUIRED" = inserted."IS_PST_REQUIRED",
      "IS_PAYMENT_APPROVED" = inserted."IS_PAYMENT_APPROVED",
      "IS_PAYMENT_FORWARDED" = inserted."IS_PAYMENT_FORWARDED",
      "IS_DISABLED" = inserted."IS_DISABLED",
      "CONCURRENCY_CONTROL_NUMBER" = inserted."CONCURRENCY_CONTROL_NUMBER",
      "APP_LAST_UPDATE_TIMESTAMP" = inserted."APP_LAST_UPDATE_TIMESTAMP",
      "APP_LAST_UPDATE_USERID" = inserted."APP_LAST_UPDATE_USERID",
      "APP_LAST_UPDATE_USER_GUID" = inserted."APP_LAST_UPDATE_USER_GUID",
      "APP_LAST_UPDATE_USER_DIRECTORY" = inserted."APP_LAST_UPDATE_USER_DIRECTORY"
    , DB_LAST_UPDATE_TIMESTAMP = getutcdate()
    , DB_LAST_UPDATE_USERID = user_name()
    from PIMS_MANAGEMENT_ACTIVITY_INVOICE
    inner join inserted
    on (PIMS_MANAGEMENT_ACTIVITY_INVOICE.MANAGEMENT_ACTIVITY_INVOICE_ID = inserted.MANAGEMENT_ACTIVITY_INVOICE_ID);

END TRY
BEGIN CATCH
   IF @@trancount > 0 ROLLBACK TRANSACTION
   EXEC pims_error_handling
END CATCH;

GO
IF @@ERROR <> 0 SET NOEXEC ON
GO

